NEW_FILES["company-memberships/company-memberships.service.ts"] = "import {\n  ConflictException,\n  ForbiddenException,\n  Injectable,\n  NotFoundException,\n} from '@nestjs/common';\nimport { UserRole } from '@vitatech/shared';\n\nimport type { AuthUser } from '../auth/types/auth-user.type';\nimport {\n  AUDIT_ACTIONS,\n  AUDIT_ENTITIES,\n} from '../audit-logs/audit-log.constants';\nimport { AuditLogsService } from '../audit-logs/audit-logs.service';\nimport { PrismaService } from '../database/prisma.service';\nimport { UserRole as PrismaUserRole } from '../generated/prisma/client';\nimport { CreateMembershipDto } from './dto/create-membership.dto';\nimport { QueryMembershipsDto } from './dto/query-memberships.dto';\n\n/**\n * Roles que pueden ser vinculados a una empresa/sede via CompanyMembership.\n * ADMIN y SUPER_ADMIN se manejan por otro camino (users.service.ts), porque\n * su relacion con una empresa tiene una semantica distinta (administran una\n * empresa, no estan \"asignados\" a ella).\n */\nconst ASSIGNABLE_ROLES: PrismaUserRole[] = [\n  PrismaUserRole.TECHNICIAN,\n  PrismaUserRole.VIEWER,\n];\n\n@Injectable()\nexport class CompanyMembershipsService {\n  constructor(\n    private readonly prisma: PrismaService,\n    private readonly auditLogsService: AuditLogsService,\n  ) {}\n\n  /**\n   * Pool global de usuarios asignables (TECHNICIAN/VIEWER), sin filtrar por\n   * empresa: es intencional, para que un Admin pueda encontrar y vincular a\n   * un tecnico que ya existe en el sistema (de cualquier empresa) en vez de\n   * crear un duplicado.\n   */\n  async searchAssignableUsers(currentUser: AuthUser, search?: string) {\n    this.assertCanManageMemberships(currentUser);\n\n    const query = search?.trim();\n\n    return this.prisma.user.findMany({\n      where: {\n        role: { in: ASSIGNABLE_ROLES },\n        isActive: true,\n        ...(query\n          ? {\n              OR: [\n                { name: { contains: query, mode: 'insensitive' } },\n                { email: { contains: query, mode: 'insensitive' } },\n              ],\n            }\n          : {}),\n      },\n      select: {\n        id: true,\n        name: true,\n        email: true,\n        role: true,\n        companyId: true,\n      },\n      take: 20,\n      orderBy: { name: 'asc' },\n    });\n  }\n\n  async findAll(currentUser: AuthUser, query: QueryMembershipsDto) {\n    const companyId = this.resolveCompanyIdForRead(currentUser, query.companyId);\n\n    return this.prisma.companyMembership.findMany({\n      where: { companyId },\n      include: {\n        user: {\n          select: { id: true, name: true, email: true, role: true },\n        },\n        site: { select: { id: true, name: true } },\n      },\n      orderBy: { assignedAt: 'desc' },\n    });\n  }\n\n  async create(currentUser: AuthUser, dto: CreateMembershipDto) {\n    this.assertCanManageMemberships(currentUser);\n    this.assertCompanyIsManageable(currentUser, dto.companyId);\n\n    const targetUser = await this.prisma.user.findUnique({\n      where: { id: dto.userId },\n    });\n\n    if (!targetUser || !targetUser.isActive) {\n      throw new NotFoundException('User not found');\n    }\n\n    if (!ASSIGNABLE_ROLES.includes(targetUser.role)) {\n      throw new ForbiddenException(\n        'Only TECHNICIAN or VIEWER users can be linked via memberships',\n      );\n    }\n\n    if (dto.siteId) {\n      const site = await this.prisma.site.findUnique({\n        where: { id: dto.siteId },\n      });\n\n      if (!site || site.companyId !== dto.companyId) {\n        throw new NotFoundException('Site not found for this company');\n      }\n    }\n\n    const existing = await this.prisma.companyMembership.findFirst({\n      where: {\n        userId: dto.userId,\n        companyId: dto.companyId,\n        siteId: dto.siteId ?? null,\n        status: 'ACTIVE',\n      },\n    });\n\n    if (existing) {\n      throw new ConflictException(\n        'This user already has an active membership for this company/site',\n      );\n    }\n\n    const membership = await this.prisma.companyMembership.create({\n      data: {\n        userId: dto.userId,\n        companyId: dto.companyId,\n        siteId: dto.siteId,\n        assignedById: currentUser.id,\n      },\n      include: {\n        user: {\n          select: { id: true, name: true, email: true, role: true },\n        },\n        site: { select: { id: true, name: true } },\n      },\n    });\n\n    await this.auditLogsService.create({\n      userId: currentUser.id,\n      action: AUDIT_ACTIONS.MEMBERSHIP_CREATED,\n      entity: AUDIT_ENTITIES.COMPANY_MEMBERSHIP,\n      entityId: membership.id,\n      newValue: {\n        userId: dto.userId,\n        companyId: dto.companyId,\n        siteId: dto.siteId ?? null,\n      },\n    });\n\n    return membership;\n  }\n\n  async revoke(currentUser: AuthUser, membershipId: string) {\n    this.assertCanManageMemberships(currentUser);\n\n    const membership = await this.prisma.companyMembership.findUnique({\n      where: { id: membershipId },\n    });\n\n    if (!membership) {\n      throw new NotFoundException('Membership not found');\n    }\n\n    this.assertCompanyIsManageable(currentUser, membership.companyId);\n\n    if (membership.status === 'INACTIVE') {\n      return membership;\n    }\n\n    const updated = await this.prisma.companyMembership.update({\n      where: { id: membershipId },\n      data: { status: 'INACTIVE', revokedAt: new Date() },\n    });\n\n    await this.auditLogsService.create({\n      userId: currentUser.id,\n      action: AUDIT_ACTIONS.MEMBERSHIP_REVOKED,\n      entity: AUDIT_ENTITIES.COMPANY_MEMBERSHIP,\n      entityId: membership.id,\n      oldValue: { status: membership.status },\n      newValue: { status: 'INACTIVE' },\n    });\n\n    return updated;\n  }\n\n  private assertCanManageMemberships(currentUser: AuthUser) {\n    if (\n      currentUser.role !== UserRole.SUPER_ADMIN &&\n      currentUser.role !== UserRole.ADMIN\n    ) {\n      throw new ForbiddenException('Insufficient permissions');\n    }\n  }\n\n  /**\n   * ADMIN solo puede gestionar membresias de su propia empresa. SUPER_ADMIN\n   * puede gestionar cualquiera (necesita pasar companyId explicitamente).\n   */\n  private assertCompanyIsManageable(currentUser: AuthUser, companyId: string) {\n    if (currentUser.role === UserRole.SUPER_ADMIN) {\n      return;\n    }\n\n    if (currentUser.companyId !== companyId) {\n      throw new ForbiddenException(\n        'You can only manage memberships for your own company',\n      );\n    }\n  }\n\n  private resolveCompanyIdForRead(\n    currentUser: AuthUser,\n    requestedCompanyId?: string,\n  ): string {\n    if (currentUser.role === UserRole.SUPER_ADMIN) {\n      if (!requestedCompanyId) {\n        throw new ForbiddenException('companyId query param is required');\n      }\n\n      return requestedCompanyId;\n    }\n\n    if (currentUser.role !== UserRole.ADMIN || !currentUser.companyId) {\n      throw new ForbiddenException('Insufficient permissions');\n    }\n\n    return currentUser.companyId;\n  }\n}\n"
NEW_FILES["company-memberships/company-memberships.controller.ts"] = "import {\n  Body,\n  Controller,\n  Get,\n  Param,\n  Patch,\n  Post,\n  Query,\n  UseGuards,\n} from '@nestjs/common';\nimport { ApiBearerAuth, ApiOkResponse, ApiTags } from '@nestjs/swagger';\nimport { UserRole } from '@vitatech/shared';\n\nimport type { AuthUser } from '../auth/types/auth-user.type';\nimport { CurrentUser } from '../common/decorators/current-user.decorator';\nimport { Roles } from '../common/decorators/roles.decorator';\nimport { JwtAuthGuard } from '../common/guards/jwt-auth.guard';\nimport { RolesGuard } from '../common/guards/roles.guard';\nimport { CompanyMembershipsService } from './company-memberships.service';\nimport { CreateMembershipDto } from './dto/create-membership.dto';\nimport { QueryMembershipsDto } from './dto/query-memberships.dto';\nimport { SearchAssignableUsersDto } from './dto/search-assignable-users.dto';\n\nconst MEMBERSHIP_MANAGER_ROLES = [UserRole.SUPER_ADMIN, UserRole.ADMIN];\n\n@ApiTags('company-memberships')\n@ApiBearerAuth()\n@Controller('company-memberships')\n@UseGuards(JwtAuthGuard, RolesGuard)\nexport class CompanyMembershipsController {\n  constructor(\n    private readonly companyMembershipsService: CompanyMembershipsService,\n  ) {}\n\n  @Get('search-users')\n  @Roles(...MEMBERSHIP_MANAGER_ROLES)\n  @ApiOkResponse({\n    description:\n      'Pool global de usuarios TECHNICIAN/VIEWER que pueden vincularse a una empresa.',\n  })\n  searchUsers(\n    @CurrentUser() user: AuthUser,\n    @Query() query: SearchAssignableUsersDto,\n  ) {\n    return this.companyMembershipsService.searchAssignableUsers(\n      user,\n      query.search,\n    );\n  }\n\n  @Get()\n  @Roles(...MEMBERSHIP_MANAGER_ROLES)\n  @ApiOkResponse({ description: 'Membresias de una empresa.' })\n  findAll(@CurrentUser() user: AuthUser, @Query() query: QueryMembershipsDto) {\n    return this.companyMembershipsService.findAll(user, query);\n  }\n\n  @Post()\n  @Roles(...MEMBERSHIP_MANAGER_ROLES)\n  @ApiOkResponse({ description: 'Vincula un usuario a una empresa/sede.' })\n  create(@CurrentUser() user: AuthUser, @Body() dto: CreateMembershipDto) {\n    return this.companyMembershipsService.create(user, dto);\n  }\n\n  @Patch(':id/revoke')\n  @Roles(...MEMBERSHIP_MANAGER_ROLES)\n  @ApiOkResponse({ description: 'Revoca (desactiva) una membresia.' })\n  revoke(@CurrentUser() user: AuthUser, @Param('id') id: string) {\n    return this.companyMembershipsService.revoke(user, id);\n  }\n}\n"
NEW_FILES["company-memberships/company-memberships.module.ts"] = "import { Module } from '@nestjs/common';\nimport { JwtModule } from '@nestjs/jwt';\n\nimport { AuditLogsModule } from '../audit-logs/audit-logs.module';\nimport { CompanyMembershipsController } from './company-memberships.controller';\nimport { CompanyMembershipsService } from './company-memberships.service';\n\n@Module({\n  imports: [JwtModule.register({}), AuditLogsModule],\n  controllers: [CompanyMembershipsController],\n  providers: [CompanyMembershipsService],\n  exports: [CompanyMembershipsService],\n})\nexport class CompanyMembershipsModule {}\n"
NEW_FILES["company-memberships/company-memberships.service.spec.ts"] = "jest.mock('../generated/prisma/client', () => ({\n  PrismaClient: class PrismaClient {},\n  UserRole: {\n    SUPER_ADMIN: 'SUPER_ADMIN',\n    ADMIN: 'ADMIN',\n    TECHNICIAN: 'TECHNICIAN',\n    VIEWER: 'VIEWER',\n  },\n}));\n\nimport { ConflictException, ForbiddenException, NotFoundException } from '@nestjs/common';\n\nimport type { AuthUser } from '../auth/types/auth-user.type';\nimport { PrismaService } from '../database/prisma.service';\nimport { CompanyMembershipsService } from './company-memberships.service';\n\ndescribe('CompanyMembershipsService RBAC', () => {\n  const companyAId = 'company-a';\n  const companyBId = 'company-b';\n\n  const currentUser = (\n    role: AuthUser['role'],\n    companyId: string | null,\n  ): AuthUser => ({\n    id: `${role.toLowerCase()}-user`,\n    name: `${role} Demo`,\n    email: `${role.toLowerCase()}@vitatech.local`,\n    role,\n    companyId,\n    companyIds: [],\n  });\n\n  const technician = {\n    id: 'tech-1',\n    name: 'Demo Technician',\n    email: 'tech@vitatech.local',\n    role: 'TECHNICIAN',\n    companyId: null,\n    isActive: true,\n  };\n\n  const admin = {\n    id: 'admin-1',\n    name: 'Demo Admin',\n    email: 'admin@vitatech.local',\n    role: 'ADMIN',\n    companyId: companyAId,\n    isActive: true,\n  };\n\n  const createService = () => {\n    const prisma = {\n      user: {\n        findMany: jest.fn(),\n        findUnique: jest.fn(),\n      },\n      site: {\n        findUnique: jest.fn(),\n      },\n      companyMembership: {\n        findFirst: jest.fn(),\n        findMany: jest.fn(),\n        findUnique: jest.fn(),\n        create: jest.fn(),\n        update: jest.fn(),\n      },\n    };\n    const auditLogsService = {\n      create: jest.fn().mockResolvedValue(undefined),\n    };\n    const service = new CompanyMembershipsService(\n      prisma as unknown as PrismaService,\n      auditLogsService as never,\n    );\n\n    return { prisma, service, auditLogsService };\n  };\n\n  it('prevents TECHNICIAN and VIEWER from managing memberships', async () => {\n    const { service } = createService();\n\n    await expect(\n      service.create(currentUser('TECHNICIAN' as never, companyAId), {\n        userId: 'tech-2',\n        companyId: companyAId,\n      }),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n\n    await expect(\n      service.searchAssignableUsers(currentUser('VIEWER' as never, companyAId)),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n  });\n\n  it('prevents ADMIN from creating a membership for another company', async () => {\n    const { service } = createService();\n\n    await expect(\n      service.create(currentUser('ADMIN' as never, companyAId), {\n        userId: 'tech-1',\n        companyId: companyBId,\n      }),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n  });\n\n  it('rejects linking a user whose role is not TECHNICIAN/VIEWER', async () => {\n    const { prisma, service } = createService();\n    prisma.user.findUnique.mockResolvedValue(admin);\n\n    await expect(\n      service.create(currentUser('ADMIN' as never, companyAId), {\n        userId: admin.id,\n        companyId: companyAId,\n      }),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n  });\n\n  it('rejects a site that does not belong to the target company', async () => {\n    const { prisma, service } = createService();\n    prisma.user.findUnique.mockResolvedValue(technician);\n    prisma.site.findUnique.mockResolvedValue({ id: 'site-1', companyId: companyBId });\n\n    await expect(\n      service.create(currentUser('ADMIN' as never, companyAId), {\n        userId: technician.id,\n        companyId: companyAId,\n        siteId: 'site-1',\n      }),\n    ).rejects.toBeInstanceOf(NotFoundException);\n  });\n\n  it('rejects a duplicate active membership for the same user/company/site', async () => {\n    const { prisma, service } = createService();\n    prisma.user.findUnique.mockResolvedValue(technician);\n    prisma.companyMembership.findFirst.mockResolvedValue({ id: 'existing' });\n\n    await expect(\n      service.create(currentUser('ADMIN' as never, companyAId), {\n        userId: technician.id,\n        companyId: companyAId,\n      }),\n    ).rejects.toBeInstanceOf(ConflictException);\n  });\n\n  it('allows ADMIN to create a membership for a TECHNICIAN in their own company', async () => {\n    const { prisma, service, auditLogsService } = createService();\n    prisma.user.findUnique.mockResolvedValue(technician);\n    prisma.companyMembership.findFirst.mockResolvedValue(null);\n    prisma.companyMembership.create.mockResolvedValue({\n      id: 'membership-1',\n      userId: technician.id,\n      companyId: companyAId,\n      siteId: null,\n      status: 'ACTIVE',\n    });\n\n    const result = await service.create(\n      currentUser('ADMIN' as never, companyAId),\n      { userId: technician.id, companyId: companyAId },\n    );\n\n    expect(result.id).toBe('membership-1');\n    expect(prisma.companyMembership.create).toHaveBeenCalledWith(\n      expect.objectContaining({\n        data: expect.objectContaining({\n          userId: technician.id,\n          companyId: companyAId,\n          assignedById: `admin-user`,\n        }),\n      }),\n    );\n    expect(auditLogsService.create).toHaveBeenCalledWith(\n      expect.objectContaining({ action: 'MEMBERSHIP_CREATED' }),\n    );\n  });\n\n  it('allows SUPER_ADMIN to create a membership for any company', async () => {\n    const { prisma, service } = createService();\n    prisma.user.findUnique.mockResolvedValue(technician);\n    prisma.companyMembership.findFirst.mockResolvedValue(null);\n    prisma.companyMembership.create.mockResolvedValue({\n      id: 'membership-2',\n      userId: technician.id,\n      companyId: companyBId,\n      siteId: null,\n      status: 'ACTIVE',\n    });\n\n    await expect(\n      service.create(currentUser('SUPER_ADMIN' as never, null), {\n        userId: technician.id,\n        companyId: companyBId,\n      }),\n    ).resolves.toMatchObject({ id: 'membership-2' });\n  });\n\n  it('prevents ADMIN from revoking a membership of another company', async () => {\n    const { prisma, service } = createService();\n    prisma.companyMembership.findUnique.mockResolvedValue({\n      id: 'membership-3',\n      companyId: companyBId,\n      status: 'ACTIVE',\n    });\n\n    await expect(\n      service.revoke(currentUser('ADMIN' as never, companyAId), 'membership-3'),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n  });\n\n  it('requires companyId in the query for SUPER_ADMIN listings', async () => {\n    const { service } = createService();\n\n    await expect(\n      service.findAll(currentUser('SUPER_ADMIN' as never, null), {}),\n    ).rejects.toBeInstanceOf(ForbiddenException);\n  });\n\n  it('scopes ADMIN membership listings to their own company regardless of query', async () => {\n    const { prisma, service } = createService();\n    prisma.companyMembership.findMany.mockResolvedValue([]);\n\n    await service.findAll(currentUser('ADMIN' as never, companyAId), {\n      companyId: companyBId,\n    });\n\n    expect(prisma.companyMembership.findMany).toHaveBeenCalledWith(\n      expect.objectContaining({ where: { companyId: companyAId } }),\n    );\n  });\n});\n"

for relpath, content in NEW_FILES.items():
    full = os.path.join(SRC, relpath)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, 'w', encoding='utf-8') as fh:
        fh.write(content)
    print(f'OK (nuevo): {full}')

def replace_once(path, old, new, label):
    with open(path, "r", encoding="utf-8") as f:
        content = f.read()
    count = content.count(old)
    if count != 1:
        print(f"FALLO [{label}] en {path}: se esperaba 1 coincidencia, se encontraron {count}")
        sys.exit(1)
    content = content.replace(old, new)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"OK: {path} [{label}]")

